@using sv_b2e12be3fdc04b978a9f77a73b2ed1c5.Models

<div class="step-indicator">
    @for (int i = 0; i < StepNames.Count; i++)
    {
        var step = i;
        var isCurrent = step == CurrentStep;
        var isCompleted = CompletedSteps.Contains(step);
        var cssClass = isCurrent ? "step active" : isCompleted ? "step completed" : "step";

        <div class="@cssClass" @onclick="() => HandleStepClick(step)" role="button">
            <div class="step-circle">
                @if (isCompleted)
                {
                    <span>&#10003;</span>
                }
                else
                {
                    <span>@(step + 1)</span>
                }
            </div>
            <span class="step-label">@StepNames[step]</span>
        </div>

        @if (step < StepNames.Count - 1)
        {
            <div class="step-connector @(isCompleted ? "completed" : "")"></div>
        }
    }
</div>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter, EditorRequired] public IReadOnlyList<string> StepNames { get; set; } = [];
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private async Task HandleStepClick(int step)
    {
        if (CompletedSteps.Contains(step))
        {
            await OnStepClicked.InvokeAsync(step);
        }
    }
}

@using sv_b2e12be3fdc04b978a9f77a73b2ed1c5.Models

<div class="reference-form">
    <div class="entry-header">
        <h5>Reference @(Index + 1)</h5>
        @if (ShowRemove)
        {
            <button type="button" class="btn btn-outline-danger btn-sm" @onclick="() => OnRemove.InvokeAsync()">Remove</button>
        }
    </div>

    <div class="form-row">
        <div class="form-group">
            <label>Full Name</label>
            <input type="text" class="form-control" @bind="Reference.Name" />
        </div>
        <div class="form-group">
            <label>Relationship</label>
            <input type="text" class="form-control" @bind="Reference.Relationship" />
        </div>
    </div>

    <div class="form-row">
        <div class="form-group">
            <label>Email</label>
            <input type="email" class="form-control" @bind="Reference.Email" />
        </div>
        <div class="form-group">
            <label>Phone</label>
            <input type="tel" class="form-control" @bind="Reference.Phone" />
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public ReferenceModel Reference { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
}

