@using sv_b2e12be3fdc04b978a9f77a73b2ed1c5.Models

<div class="step-content">
    <h3>Personal Information</h3>

    <div class="form-group">
        <label>Full Name <span class="required">*</span></label>
        <input type="text" class="form-control" @bind="Model.FullName" />
    </div>

    <div class="form-group">
        <label>Email <span class="required">*</span></label>
        <input type="email" class="form-control" @bind="Model.Email" />
        @if (!string.IsNullOrEmpty(_emailError))
        {
            <span class="field-error">@_emailError</span>
        }
    </div>

    <div class="form-group">
        <label>Phone <span class="required">*</span></label>
        <input type="tel" class="form-control" @bind="Model.Phone" />
    </div>

    <div class="form-group">
        <label>Address <span class="required">*</span></label>
        <textarea class="form-control" rows="2" @bind="Model.Address"></textarea>
    </div>

    @if (!string.IsNullOrEmpty(_validationError))
    {
        <div class="validation-error">@_validationError</div>
    }

    <div class="step-buttons">
        <div></div>
        <button type="button" class="btn btn-primary" @onclick="HandleNext" disabled="@_isValidating">
            @if (_isValidating)
            {
                <span>Validating...</span>
            }
            else
            {
                <span>Next</span>
            }
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }

    private string? _validationError;
    private string? _emailError;
    private bool _isValidating;

    private async Task HandleNext()
    {
        _validationError = null;
        _emailError = null;

        if (string.IsNullOrWhiteSpace(Model.FullName) ||
            string.IsNullOrWhiteSpace(Model.Email) ||
            string.IsNullOrWhiteSpace(Model.Phone) ||
            string.IsNullOrWhiteSpace(Model.Address))
        {
            _validationError = "All fields are required.";
            return;
        }

        _isValidating = true;
        try
        {
            var isValidEmail = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!isValidEmail)
            {
                _emailError = "Please enter a valid email address.";
                return;
            }

            await OnNext.InvokeAsync();
        }
        finally
        {
            _isValidating = false;
        }
    }
}

@using sv_b2e12be3fdc04b978a9f77a73b2ed1c5.Models

<div class="step-content">
    <h3>Work History</h3>

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryForm Entry="Entries[index]"
                       Index="index"
                       ShowRemove="Entries.Count > 1"
                       OnRemove="() => RemoveEntry(index)" />
    }

    <button type="button" class="btn btn-outline-primary" @onclick="AddEntry">
        + Add Another Position
    </button>

    @if (!string.IsNullOrEmpty(_validationError))
    {
        <div class="validation-error">@_validationError</div>
    }

    <div class="step-buttons">
        <button type="button" class="btn btn-secondary" @onclick="OnBack">Back</button>
        <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? _validationError;

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        _validationError = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) ||
                string.IsNullOrWhiteSpace(entry.Title) ||
                entry.StartDate == null)
            {
                _validationError = "Each position requires a company name, job title, and start date.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_b2e12be3fdc04b978a9f77a73b2ed1c5.Models

<div class="step-content">
    <h3>References</h3>

    @for (int i = 0; i < References.Count; i++)
    {
        var index = i;
        <ReferenceForm Reference="References[index]"
                       Index="index"
                       ShowRemove="References.Count > 2"
                       OnRemove="() => RemoveReference(index)" />
    }

    @if (References.Count < 3)
    {
        <button type="button" class="btn btn-outline-primary" @onclick="AddReference">
