{"file_text": "<div class="step-content">
    <h3>Cover Letter</h3>

    <div class="form-group">
        <label>Write your cover letter</label>
        <textarea class="form-control cover-letter-textarea"
                  rows="12"
                  maxlength="@MaxLength"
                  @bind="CoverLetter"
                  @bind:event="oninput"
                  @bind:after="OnChanged"></textarea>
        <div class="char-count @(CoverLetter.Length > MaxLength ? "over-limit" : "")">
            @CoverLetter.Length / @MaxLength characters
        </div>
    </div>

    @if (!string.IsNullOrEmpty(_validationError))
    {
        <div class="validation-error">@_validationError</div>
    }

    <div class="step-buttons">
        <button type="button" class="btn btn-secondary" @onclick="OnBack">Back</button>
        <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private const int MaxLength = 2000;
    private string? _validationError;

    private async Task OnChanged()
    {
        await CoverLetterChanged.InvokeAsync(CoverLetter);
    }

    private async Task HandleNext()
    {
        _validationError = null;

        if (string.IsNullOrWhiteSpace(CoverLetter))
        {
            _validationError = "A cover letter is required.";
            return;
        }

        await OnNext.InvokeAsync();
    }
}
