toolArgs.file_text:
@using sv_b2e12be3fdc04b978a9f77a73b2ed1c5.Models

<div class="step-content">
    <h3>Review & Submit</h3>

    @if (_submitted)
    {
        <div class="confirmation">
            <h4>&#10003; Application Submitted!</h4>
            <p>Your application has been received. Your application ID is <strong>@_applicationId</strong>.</p>
        </div>
    }
    else
    {
        <div class="review-section">
            <div class="review-header">
                <h4>Personal Information</h4>
                <button type="button" class="btn-link" @onclick='() => OnEditSection.InvokeAsync(0)'>Edit</button>
            </div>
            <dl>
                <dt>Name</dt><dd>@Personal.FullName</dd>
                <dt>Email</dt><dd>@Personal.Email</dd>
                <dt>Phone</dt><dd>@Personal.Phone</dd>
                <dt>Address</dt><dd>@Personal.Address</dd>
            </dl>
        </div>

        <div class="review-section">
            <div class="review-header">
                <h4>Work History</h4>
                <button type="button" class="btn-link" @onclick='() => OnEditSection.InvokeAsync(1)'>Edit</button>
            </div>
            @foreach (var entry in WorkEntries)
            {
                <div class="review-entry">
                    <strong>@entry.Title</strong> at @entry.Company
                    <br />
                    <span class="text-muted">
                        @entry.StartDate?.ToString("MMM yyyy") &ndash;
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </span>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p>@entry.Description</p>
                    }
                </div>
            }
        </div>

        <div class="review-section">
            <div class="review-header">
                <h4>References</h4>
                <button type="button" class="btn-link" @onclick='() => OnEditSection.InvokeAsync(2)'>Edit</button>
            </div>
            @foreach (var reference in References)
            {
                <div class="review-entry">
                    <strong>@reference.Name</strong> (@reference.Relationship)
                    <br />
                    @reference.Email &middot; @reference.Phone
                </div>
            }
        </div>

        <div class="review-section">
            <div class="review-header">
                <h4>Cover Letter</h4>
                <button type="button" class="btn-link" @onclick='() => OnEditSection.InvokeAsync(3)'>Edit</button>
            </div>
            <p class="cover-letter-preview">@CoverLetter</p>
        </div>

        @if (!string.IsNullOrEmpty(_errorMessage))
        {
            <div class="validation-error">@_errorMessage</div>
        }

        <div class="step-buttons">
            <button type="button" class="btn btn-secondary" @onclick="OnBack">Back</button>
            <button type="button" class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@_isSubmitting">
                @(_isSubmitting ? "Submitting..." : "Submit Application")
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;
    [Parameter] public EventCallback<int> OnEditSection { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private bool _isSubmitting;
    private bool _submitted;
    private int _applicationId;
    private string? _errorMessage;

    private async Task HandleSubmit()
    {
        _isSubmitting = true;
        _errorMessage = null;

        try
        {
            var application = new JobApplication(
                Personal.ToRecord(),
                new WorkHistory(WorkEntries.Select(e => e.ToRecord()).ToList()),
                References.Select(r => r.ToRecord()).ToList(),
                CoverLetter
            );

            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
            _submitted = true;
        }
        catch (Exception ex)
        {
            _errorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            _isSubmitting = false;
        }
    }
}

