arguments.file_text:
@page "/apply"
@using sv_b2e12be3fdc04b978a9f77a73b2ed1c5.Models
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="apply-page">
    <h2>Job Application</h2>

    <StepIndicator CurrentStep="_currentStep"
                   CompletedSteps="_completedSteps"
                   StepNames="_stepNames"
                   OnStepClicked="GoToStep" />

    @switch (_currentStep)
    {
        case 0:
            <PersonalInfoStep Model="_personalInfo"
                              ApplicationService="ApplicationService"
                              OnNext="NextStep" />
            break;
        case 1:
            <WorkHistoryStep Entries="_workEntries"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;
        case 2:
            <ReferencesStep References="_references"
                            OnNext="NextStep"
                            OnBack="PreviousStep" />
            break;
        case 3:
            <CoverLetterStep CoverLetter="@_coverLetter"
                             CoverLetterChanged="val => _coverLetter = val"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;
        case 4:
            <ReviewStep Personal="_personalInfo"
                        WorkEntries="_workEntries"
                        References="_references"
                        CoverLetter="@_coverLetter"
                        ApplicationService="ApplicationService"
                        OnEditSection="GoToStep"
                        OnBack="PreviousStep" />
            break;
    }
</div>

@code {
    private static readonly List<string> _stepNames =
    [
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    ];

    private int _currentStep;
    private readonly HashSet<int> _completedSteps = new();

    private readonly PersonalInfoModel _personalInfo = new();
    private readonly List<WorkEntryModel> _workEntries = [new WorkEntryModel()];
    private readonly List<ReferenceModel> _references = [new ReferenceModel(), new ReferenceModel()];
    private string _coverLetter = "";

    private void NextStep()
    {
        _completedSteps.Add(_currentStep);
        if (_currentStep < _stepNames.Count - 1)
        {
            _currentStep++;
        }
    }

    private void PreviousStep()
    {
        if (_currentStep > 0)
        {
            _currentStep--;
        }
    }

    private void GoToStep(int step)
    {
        _currentStep = step;
    }
}

.apply-page {
    max-width: 720px;
    margin: 0 auto;
    padding: 2rem 1rem;
}

/* Step Indicator */
::deep .step-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 2rem;
    gap: 0;
}

::deep .step {
    display: flex;
    flex-direction: column;
    align-items: center;
    cursor: default;
    opacity: 0.4;
    transition: opacity 0.2s;
}

::deep .step.active {
    opacity: 1;
}

::deep .step.completed {
    opacity: 0.85;
    cursor: pointer;
}

::deep .step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    background: #dee2e6;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.9rem;
    color: #495057;
    margin-bottom: 0.25rem;
}

::deep .step.active .step-circle {
    background: #0d6efd;
    color: #fff;
}

::deep .step.completed .step-circle {
    background: #198754;
    color: #fff;
}

::deep .step-label {
    font-size: 0.75rem;
    text-align: center;
    max-width: 80px;
    color: #6c757d;
}

::deep .step.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

::deep .step-connector {
    flex: 1;
    height: 2px;
    background: #dee2e6;
    margin: 0 0.25rem;
    margin-bottom: 1.25rem;
    min-width: 24px;
}

::deep .step-connector.completed {
    background: #198754;
}

/* Step Content */
::deep .step-content {
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: 1.5rem;
}

::deep .step-content h3 {
    margin-top: 0;
    margin-bottom: 1.25rem;
    color: #212529;
}

/* Form elements */
::deep .form-group {
    margin-bottom: 1rem;
}

::deep .form-group label {
    display: block;
    font-weight: 500;
    margin-bottom: 0.25rem;
    color: #495057;
}

::deep .form-control {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    font-size: 1rem;
    box-sizing: border-box;
}

::deep .form-control:focus {
    border-color: #86b7fe;
    outline: 0;
    box-shadow: 0 0 0 0.2rem rgba(13, 110, 253, 0.25);
}

::deep .form-row {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 1rem;
}

::deep .required {
    color: #dc3545;
}

::deep .field-error {
    color: #dc3545;
    font-size: 0.85rem;
    margin-top: 0.25rem;
    display: block;
}

::deep .validation-error {
    background: #f8d7da;
    color: #842029;
    padding: 0.75rem 1rem;
    border-radius: 4px;
    margin: 1rem 0;
    font-size: 0.9rem;
}

/* Buttons */
::deep .step-buttons {
    display: flex;
    justify-content: space-between;
    margin-top: 1.5rem;
    padding-top: 1rem;
    border-top: 1px solid #e9ecef;
}

::deep .btn {
    padding: 0.5rem 1.25rem;
    border-radius: 4px;
    font-size: 1rem;
    cursor: pointer;
    border: 1px solid transparent;
    transition: background 0.15s;
}

::deep .btn-primary {
    background: #0d6efd;
    color: #fff;
}

::deep .btn-primary:hover {
    background: #0b5ed7;
}

::deep .btn-primary:disabled {
    background: #6c9eeb;
    cursor: not-allowed;
}

::deep .btn-secondary {
    background: #6c757d;
    color: #fff;
}

::deep .btn-secondary:hover {
    background: #5c636a;
}

::deep .btn-success {
    background: #198754;
    color: #fff;
}

::deep .btn-success:hover {
    background: #157347;
}

::deep .btn-success:disabled {
    background: #5cb085;
    cursor: not-allowed;
}

::deep .btn-lg {
    padding: 0.65rem 1.75rem;
    font-size: 1.1rem;
}

::deep .btn-outline-primary {
    background: transparent;
    color: #0d6efd;
    border: 1px solid #0d6efd;
}

::deep .btn-outline-primary:hover {
    background: #0d6efd;
    color: #fff;
}

::deep .btn-outline-danger {
    background: transparent;
    color: #dc3545;
    border: 1px solid #dc3545;
}

::deep .btn-outline-danger:hover {
    background: #dc3545;
    color: #fff;
}

::deep .btn-sm {
    padding: 0.25rem 0.75rem;
    font-size: 0.85rem;
}

::deep .btn-link {
    background: none;
    border: none;
    color: #0d6efd;
    cursor: pointer;
    font-size: 0.9rem;
    padding: 0;
    text-decoration: underline;
}

::deep .btn-link:hover {
    color: #0a58ca;
}

/* Work entry / Reference forms */
::deep .work-entry-form,
::deep .reference-form {
    border: 1px solid #e9ecef;
    border-radius: 6px;
    padding: 1rem;
    margin-bottom: 1rem;
    background: #f8f9fa;
}

::deep .entry-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.75rem;
}

::deep .entry-header h5 {
    margin: 0;
    color: #495057;
}

::deep .checkbox-label {
    display: inline-flex !important;
    align-items: center;
    gap: 0.4rem;
    font-weight: 400 !important;
    margin-top: 0.35rem;
    font-size: 0.9rem;
}

::deep .checkbox-label input[type="checkbox"] {
    width: auto;
}

/* Cover letter */
::deep .cover-letter-textarea {
    resize: vertical;
    min-height: 200px;
}

::deep .char-count {
    text-align: right;
    font-size: 0.85rem;
    color: #6c757d;
    margin-top: 0.25rem;
}

::deep .char-count.over-limit {
    color: #dc3545;
    font-weight: 600;
}

/* Review step */
::deep .review-section {
    border: 1px solid #e9ecef;
    border-radius: 6px;
    padding: 1rem;
    margin-bottom: 1rem;
}

::deep .review-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.5rem;
}

::deep .review-header h4 {
    margin: 0;
    font-size: 1.05rem;
}

::deep .review-section dl {
    display: grid;
    grid-template-columns: 100px 1fr;
    gap: 0.25rem 0.75rem;
    margin: 0;
}

::deep .review-section dt {
    font-weight: 600;
    color: #6c757d;
    font-size: 0.9rem;
}

::deep .review-section dd {
    margin: 0;
}

::deep .review-entry {
    padding: 0.5rem 0;
    border-bottom: 1px solid #f0f0f0;
}

::deep .review-entry:last-child {
    border-bottom: none;
}

::deep .text-muted {
    color: #6c757d;
    font-size: 0.9rem;
}

::deep .cover-letter-preview {
    white-space: pre-wrap;
    background: #f8f9fa;
    padding: 0.75rem;
    border-radius: 4px;
    font-size: 0.95rem;
}

/* Confirmation */
::deep .confirmation {
    text-align: center;
    padding: 2rem;
}

::deep .confirmation h4 {
    color: #198754;
    font-size: 1.5rem;
    margin-bottom: 1rem;
}

