    {
        _completedSteps.Add(_currentStep);
        if (_currentStep < _stepNames.Count - 1)
        {
            _currentStep++;
        }
    }

    private void PreviousStep()
    {
        if (_currentStep > 0)
        {
            _currentStep--;
        }
    }

    private void GoToStep(int step)
    {
        _currentStep = step;
    }
}
