+}
+
+::deep .review-entry:last-child {
+    border-bottom: none;
+}
+
+::deep .text-muted {
+    color: #6c757d;
+    font-size: 0.9rem;
+}
+
+::deep .cover-letter-preview {
+    white-space: pre-wrap;
+    background: #f8f9fa;
+    padding: 0.75rem;
+    border-radius: 4px;
